const defs_orbitals = {"gradients":{},"filters":{}};
function render_orbitals(ctx) {
  const cmds = commands_orbitals;
  const d = defs_orbitals;
  const s = ctx.scene;
  for (const cmd of cmds) s._commands.push(cmd);
  if (d.gradients) { for (const k in d.gradients) s._defs.gradients[k] = d.gradients[k]; }
  if (d.filters) { for (const k in d.filters) s._defs.filters[k] = d.filters[k]; }
}

