// === Vanilla JS init (replaces React component) ===
// Each layer paints its own full-canvas background rect, so compositing all 4
// just shows the topmost. We render a single layer and drop its full-bg rect
// so the canvas is transparent and composites over the page.
function initCircuitBoard(canvas, opts) {
  opts = opts || {};
  const w = opts.width || 800;
  const h = opts.height || 800;
  const layer = opts.layer || 'circuit_board';
  const transparent = opts.transparent !== false;
  const paramOverrides = Object.assign({}, opts);
  delete paramOverrides.width;
  delete paramOverrides.height;
  delete paramOverrides.seed;
  delete paramOverrides.layer;
  delete paramOverrides.transparent;

  const dpr = window.devicePixelRatio || 1;
  canvas.width = w * dpr;
  canvas.height = h * dpr;
  // Don't force inline CSS size — let the stylesheet size the canvas so
  // object-fit/responsive layouts can work while the intrinsic ratio stays w×h.
  if (opts.setInlineSize !== false && !opts.responsive) {
    canvas.style.width = w + 'px';
    canvas.style.height = h + 'px';
  }
  const ctx = canvas.getContext('2d');
  if (!ctx) return;
  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

  const math = { lerp, clamp, map, dist, angle, smoothstep, mod, createNoise2D };
  const color = { hsla, rgb, hexToRgb };
  const layerMap = {
    circuit_board: { fn: render_circuit_board, params: params_circuit_board },
    cellular_automaton: { fn: render_cellular_automaton, params: params_cellular_automaton },
    particle_trails: { fn: render_particle_trails, params: params_particle_trails },
    orbitals: { fn: render_orbitals, params: params_orbitals },
  };
  const pick = layerMap[layer] || layerMap.circuit_board;
  const currentParams = Object.assign({}, pick.params, paramOverrides);

  const scene = new Scene();
  pick.fn({ params: currentParams, size: { width: w, height: h }, scene: scene, rng: new RNG(currentParams.seed || 42), utils: { math, color } });

  // Drop the first full-canvas background rect so the canvas composites transparently
  if (transparent && scene._commands.length > 0) {
    const first = scene._commands[0];
    if (first && first.type === 'rect' && first.props &&
        first.props.x === 0 && first.props.y === 0 &&
        first.props.w === w && first.props.h === h) {
      scene._commands.shift();
    }
  }

  ctx.clearRect(0, 0, w, h);
  const renderer = new CanvasRenderer({ canvas: canvas, width: w, height: h });
  renderer.render(scene.getCommands(), scene.getDefs());
}

// Expose globally
if (typeof window !== 'undefined') {
  window.initCircuitBoard = initCircuitBoard;
}
